359	// Aggregate builds the final Output from items and entries.
360	func Aggregate(beadID, attemptID string, entries []Entry) Output {
361		out := Output{
362			SchemaVersion: SchemaVersion,
363			BeadID:        beadID,
364			AttemptID:     attemptID,
365			Items:         entries,
366		}
367		for _, e := range entries {
368			switch e.Result {
369			case ResultPass:
370				out.Summary.Pass++
371			case ResultFail:
372				out.Summary.Fail++
373			case ResultNeedsJudgment:
374				out.Summary.NeedsJudgment++
375			case ResultError:
376				out.Summary.Error++
377			}
378		}
379		return out
380	}
